import java.sql.*;
public class JavaApp
{
    public static void main(String args[]) 
    {
        try {
            Class.forName("org.postgresql.Driver");
            System.out.println("Connecting to PostgreSQL database...");

            String url = "jdbc:postgresql://localhost:5432/demo_db";
            String username = "admin";
            String password = "<PASSWORD>!";
            Connection conn = DriverManager.getConnection(url,username,password);
            
            Statement stmt = conn.createStatement();
            
            String sqlString = 
                "CREATE TABLE test_table (id INTEGER PRIMARY KEY, name VARCHAR(50));"
                + "INSERT INTO test_table VALUES(1,'Test 1');";

            System.out.println("Creating and inserting new data");
            stmt.execute(sqlString);
            stmt.close();
            
            String query = "select * from test_table;";
            ResultSet rs = stmt.executeQuery(query);
            
            while (rs.next()) {
                int id = rs.getInt("id"); 
                String name = rs.getString("name"); 
                
                System.out.println(String.format("ID: %d\tName:%s",id, name)); 
            }

            // Close connection
            conn.close();
            stmt.close();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

